  const toggleSelect = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const next = new Set(selectedIds);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setSelectedIds(next);
  };

  const toggleSelectAll = () => {
      const visibleIds = paginatedNotifications.map(n => n.id);
      const allVisibleSelected = visibleIds.every(id => selectedIds.has(id));

      const next = new Set(selectedIds);
      if (allVisibleSelected) {
          visibleIds.forEach(id => next.delete(id));
      } else {
          visibleIds.forEach(id => next.add(id));
      }
      setSelectedIds(next);
  };

  const handleMarkSelectedRead = async () => {
      if (selectedIds.size === 0) return;
      // Solo enviamos los que realmente no han sido leídos para optimizar
      const idsToUpdate = Array.from(selectedIds).filter(id => {
          const n = notifications.find(notif => notif.id === id);
          return n && !n.isRead;
      });

      if (idsToUpdate.length > 0) {
          await NotificationService.markMultipleAsRead(idsToUpdate);
      }
      setSelectedIds(new Set());
