import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { NotificationService } from '../services/firebaseBackend';
import { User, Notification } from '../types';
import { Inbox, CheckCircle, Mail, User as UserIcon, MessageSquare, AlertTriangle, CheckSquare, ArrowRight, Search, ChevronLeft, ChevronRight, Filter, Upload, Square } from 'lucide-react';

interface Props {
  user: User;
}

const ITEMS_PER_PAGE = 10;

const Buffer: React.FC<Props> = ({ user }) => {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const navigate = useNavigate();

  // UI States
  const [activeTab, setActiveTab] = useState<'PENDING' | 'HISTORY'>('PENDING');
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    setLoading(true);
    const unsubscribe = NotificationService.subscribeToNotifications(user.id, (data) => {
        setNotifications(data);
        setLoading(false);
    });

    return () => unsubscribe();
  }, [user.id]);

  // Filtrado base según la pestaña activa
  const filteredNotifications = useMemo(() => {
      return notifications.filter(n => {
          if (activeTab === 'PENDING' && n.isRead) return false;
          if (searchTerm) {
              const term = searchTerm.toLowerCase();
              return (
                  n.title.toLowerCase().includes(term) ||
                  n.message.toLowerCase().includes(term) ||
                  n.actorName.toLowerCase().includes(term)
              );
          }
          return true;
      });
  }, [notifications, activeTab, searchTerm]);

  const totalPages = Math.ceil(filteredNotifications.length / ITEMS_PER_PAGE);

  const paginatedNotifications = useMemo(() => {
      const start = (currentPage - 1) * ITEMS_PER_PAGE;
      return filteredNotifications.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredNotifications, currentPage]);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  // Handlers de Selección
  const toggleSelect = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const next = new Set(selectedIds);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setSelectedIds(next);
  };

  const toggleSelectAll = () => {
      const visibleIds = paginatedNotifications.map(n => n.id);
      const allVisibleSelected = visibleIds.every(id => selectedIds.has(id));

      const next = new Set(selectedIds);
      if (allVisibleSelected) {
          visibleIds.forEach(id => next.delete(id));
      } else {
          visibleIds.forEach(id => next.add(id));
      }
      setSelectedIds(next);
  };

  const handleMarkSelectedRead = async () => {
      if (selectedIds.size === 0) return;
      // Solo enviamos los que realmente no han sido leídos para optimizar
      // Added explicit type to idsToUpdate to avoid TypeScript inference of 'unknown[]'
      const idsToUpdate: string[] = Array.from(selectedIds).filter((id: string) => {
          const n = notifications.find(notif => notif.id === id);
          return !!(n && !n.isRead);
      });

      if (idsToUpdate.length > 0) {
          await NotificationService.markMultipleAsRead(idsToUpdate);
      }
      setSelectedIds(new Set());
  };

  const handleItemClick = async (notif: Notification, e: React.MouseEvent) => {
      // Si el click viene del área de selección, no navegar
      if ((e.target as HTMLElement).closest('.selection-trigger')) return;

      if (!notif.isRead) {
          await NotificationService.markAsRead(notif.id);
      }

      if (notif.documentId.startsWith('MTX_')) {
          navigate('/new');
      } else {
          navigate(`/doc/${notif.documentId}`);
      }
  };

  const getIcon = (type: Notification['type']) => {
      switch (type) {
          case 'ASSIGNMENT': return <UserIcon size={18} className="text-blue-500" />;
          case 'APPROVAL': return <CheckSquare size={18} className="text-green-500" />;
          case 'REJECTION': return <AlertTriangle size={18} className="text-red-500" />;
          case 'COMMENT': return <MessageSquare size={18} className="text-amber-500" />;
          case 'UPLOAD': return <Upload size={18} className="text-indigo-500" />;
          default: return <Mail size={18} className="text-slate-500" />;
      }
  };

  useEffect(() => {
      setCurrentPage(1);
      setSelectedIds(new Set());
  }, [activeTab, searchTerm]);

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando notificaciones...</div>;

  const allVisibleSelected = paginatedNotifications.length > 0 && paginatedNotifications.every(n => selectedIds.has(n.id));

  return (
    <div className="space-y-6 max-w-5xl mx-auto pb-12 animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                <Inbox className="text-indigo-600" />
                Bandeja de Entrada
            </h1>
            <p className="text-slate-500 text-sm">
                Gestiona tus avisos de asignación y cambios de estado.
            </p>
        </div>

        <div className="h-10 flex items-center">
            {selectedIds.size > 0 && (
                <button 
                    onClick={handleMarkSelectedRead}
                    className="text-xs text-white font-black uppercase tracking-widest px-5 py-2.5 bg-indigo-600 rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 flex items-center gap-2 animate-fadeIn"
                >
                    <CheckCircle size={16} />
                    Marcar como leídos ({selectedIds.size})
                </button>
            )}
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden min-h-[600px] flex flex-col">
          {/* BARRA DE HERRAMIENTAS */}
